static class JamLazyNameCons extends JamCons {
  /** Suspension for first */
  protected Suspension firstSusp;
  /** Suspension for rest */
  protected Suspension restSusp;
  public JamLazyNameCons(Suspension f, Suspension r) {
    super(null, null);
    firstSusp = f;
    restSusp = r;
  }

  @Override
  public JamVal first() { return firstSusp.eval(); }

  @Override
  public JamList rest() {
    JamVal res = restSusp.eval();
    if (res instanceof JamList) return (JamList) res;
    throw new EvalException("rest of lazy cons is not a list: " + res);
  }
}

/** Class for a lazy cons with optimization. */
static class JamLazyNeedCons extends JamLazyNameCons {
  private JamVal firstVal;
  private JamList restVal;

  public JamLazyNeedCons(Suspension f, Suspension r) { super(f, r); }

  @Override
  public JamVal first() {
    if (firstSusp != null) {
      firstVal = firstSusp.eval();
      firstSusp = null;
    }
    return firstVal;
  }

  @Override
  public JamList rest() {
    if (restSusp != null) {
      JamVal res = restSusp.eval();
      if (res instanceof JamList) {
        restVal = (JamList) res;
        restSusp = null;
      } else {
        throw new EvalException("rest of lazy cons is not a list: " + res);
      }
    }
    return restVal;
  }
}

/** Eager cons evaluation policy. Presumes that args has exactly 2 elements. */
public static final ConsPolicy EAGER = new ConsPolicy() {
  public JamVal evalCons(AST[] args, EvalVisitor ev) {
    JamVal val0 = args[0].accept(ev);
