  if (v1 == v2) return true;
  if (v1 instanceof JamCons && v2 instanceof JamCons) {
    JamCons c1 = (JamCons) v1;
    JamCons c2 = (JamCons) v2;
    return jamEquals(c1.first(), c2.first()) && jamEquals(c1.rest(), c2.rest());
  }
  return v1.equals(v2);
}

