import junit.framework.TestCase;
import java.io.*;

public class MyAssign3Test extends TestCase {
  public MyAssign3Test(String name) { super(name); }

  private void allCheck(String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals(answer, interp.valueValue().toString());
    assertEquals(answer, interp.valueName().toString());
    assertEquals(answer, interp.valueNeed().toString());
    assertEquals(answer, interp.nameValue().toString());
    assertEquals(answer, interp.nameName().toString());
    assertEquals(answer, interp.nameNeed().toString());
    assertEquals(answer, interp.needValue().toString());
    assertEquals(answer, interp.needName().toString());
    assertEquals(answer, interp.needNeed().toString());
  }

  private void lazyCheck(String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals(answer, interp.valueName().toString());
    assertEquals(answer, interp.valueNeed().toString());
    assertEquals(answer, interp.nameName().toString());
    assertEquals(answer, interp.nameNeed().toString());
    assertEquals(answer, interp.needName().toString());
    assertEquals(answer, interp.needNeed().toString());
  }

  public void testRecursiveLet() {
    String input = "let fact := map n to if n = 0 then 1 else n * fact(n - 1); in fact(5)";
    allCheck("120", input);
  }

  public void testMutualRecursion() {
    String input = "let even := map n to if n = 0 then true else odd(n - 1); " +
                   "    odd := map n to if n = 0 then false else even(n - 1); " +
                   "in even(10)";
    allCheck("true", input);
  }

  public void testInfiniteListShortCircuit() {
    String input = "let zeros := cons(0, zeros); " +
                   "    ones := cons(1, ones); " +
                   "in zeros = ones";
    lazyCheck("false", input);
  }

  public void testInfiniteListShortCircuitTrue() {
    String input = "let ones := cons(1, ones); " +
                   "in ones = ones";
    lazyCheck("true", input);
  }

  public void testDuplicateVarsInMap() {
    try {
      Interpreter interp = new Interpreter(new StringReader("map x, x to x"));
      fail("Should throw SyntaxException");
    } catch (SyntaxException e) {
      // Expected
    }
  }

  public void testDuplicateVarsInLet() {
    try {
      Interpreter interp = new Interpreter(new StringReader("let x := 1; x := 2; in x"));
      fail("Should throw SyntaxException");
    } catch (SyntaxException e) {
      // Expected
    }
  }

  public void testFreeVariable() {
    try {
      Interpreter interp = new Interpreter(new StringReader("x + 1"));
      fail("Should throw SyntaxException");
    } catch (SyntaxException e) {
      // Expected
    }
  }

  public void testLazyConsSafety() {
    // rest(cons(1, 2)) should be an error
    String input = "let x := cons(1, 2); in rest(x)";
    Interpreter interp = new Interpreter(new StringReader(input));
    try {
      interp.valueName();
      fail("Should throw EvalException");
    } catch (EvalException e) {
      // Expected
    }
  }

  public void testLazyConsEvaluation() {
    // Check that arguments are only evaluated when needed
    String input = "let x := cons(1, 1 / 0); in first(x)";
    Interpreter interp = new Interpreter(new StringReader(input));
    assertEquals("1", interp.valueName().toString());
  }
}

